%[text] # ばね-マス-ダンパ系 振動シミュレーション
%[text] 運動方程式: $m\\ddot{x} + c\\dot{x} + kx = 0$
%[text] スライダーを動かすと、グラフが自動的に更新されます。
m    = 0.1; %[control:slider:m001]{"position":[8,11]}
k    = 50; %[control:slider:k001]{"position":[8,10]}
zeta = 0.21; %[control:slider:z001]{"position":[8,12]}

omega_n = sqrt(k / m);
c       = 2 * zeta * sqrt(m * k);

if zeta < 1,         state = '不足減衰（振動）';
elseif zeta <= 1.01, state = '臨界減衰';
else,                state = '過減衰'; end

fprintf('omega_n = %.3f rad/s  |  fn = %.3f Hz  |  %s\n', ... %[output:group:9012250d] %[output:70ab9a47]
    omega_n, omega_n/(2*pi), state); %[output:group:9012250d] %[output:70ab9a47]

x0 = [1.0; 0.0];
tspan = [0, max(8, 5*2*pi/max(omega_n, 0.1))];
[t, y] = ode45(@(t,y) [y(2); -(c/m)*y(2)-(k/m)*y(1)], tspan, x0);

figure(1); clf; %[output:4032739c]
plot(t, y(:,1), 'b-', 'LineWidth', 2); %[output:4032739c]
yline(0, 'k:', 'LineWidth', 1); %[output:4032739c]
xlabel('時間  t  [s]', 'FontSize', 12); %[output:4032739c]
ylabel('変位  x  [m]', 'FontSize', 12); %[output:4032739c]
title(sprintf('m=%.2f kg | k=%.1f N/m | \\zeta=%.2f | \\omega_n=%.3f rad/s  [%s]', ... %[output:4032739c]
    m, k, zeta, omega_n, state), 'FontSize', 11); %[output:4032739c]
grid on; %[output:4032739c]

%[text] ## 理論解説
%[text] **減衰比** $\\zeta$ **による挙動の違い**
%[text] - $\\zeta \< 1$（不足減衰）：振動しながら減衰する
%[text] - $\\zeta = 1$（臨界減衰）：振動せず最速で収束する
%[text] - $\\zeta \> 1$（過減衰）：振動せずゆっくり収束する \
%[text] **固有角周波数と固有振動数**
%[text] $\\omega\_n = \\sqrt{\\frac{k}{m}}, \\qquad f\_n = \\frac{\\omega\_n}{2\\pi}$

%[appendix]{"version":"1.0"}
