%---
%[control:slider:k001]
%   data: {"defaultValue":10,"label":"ばね定数 k [N\/m]","max":50,"min":1,"run":"SectionToEnd","runOn":"ValueChanging","step":0.5}
%---
%[control:slider:z001]
%   data: {"defaultValue":0.3,"label":"減衰比 zeta [-]","max":2,"min":0,"run":"SectionToEnd","runOn":"ValueChanging","step":0.01}
